#include <iostream>

int main(int argc, char *argv[]) {
    if (argc!= 3) {
        std::cerr << "Usage: " << argv[0] << " <input file> <output file>" << std::endl;
        return 1;
    }

    // Read input file
    FILE *file = fopen("input.txt", "r");
    char buffer[1024];
    while (fscanf(file, "%[^\n]", buffer)!= EOF)
    {
        // Write output file
        fwrite(buffer, sizeof(char), 1, "output.txt");
    }}
